The fts5_api structure is defined as follows. It exposes five methods:


	 xCreateTokenizer() and xCreateTokenizer_v2(), for registering new 
       custom tokenizer implementations.

	 xFindTokenizer() and xFindTokenizer_v2(), for retrieving existing
       tokenizer implementations. This can be useful for implementing 
       "tokenizer wrappers", similar to the built-in porter tokenizer.

	 xCreateFunction(), for registering new auxiliary function
       implementations.




The two "v2" methods above are only available if the fts5_api.iVersion
field is set to 3 or greater. Attempting to access the "v2" APIs via an
fts5_api object with a lower value for iVersion results in undefined behavior.


typedef struct fts5_api fts5_api;
struct fts5_api {
  int iVersion;                   /* Currently always set to 3 */

  /* Create a new tokenizer */
  int (*xCreateTokenizer)(
    fts5_api *pApi,
    const char *zName,
    void *pUserData,
    fts5_tokenizer *pTokenizer,
    void (*xDestroy)(void*)
  );

  /* Find an existing tokenizer */
  int (*xFindTokenizer)(
    fts5_api *pApi,
    const char *zName,
    void **ppUserData,
    fts5_tokenizer *pTokenizer
  );

  /* Create a new auxiliary function */
  int (*xCreateFunction)(
    fts5_api *pApi,
    const char *zName,
    void *pUserData,
    fts5_extension_function xFunction,
    void (*xDestroy)(void*)
  );

  /* APIs below this point are only available if iVersion>=3 */

  /* Create a new tokenizer */
  int (*xCreateTokenizer_v2)(
    fts5_api *pApi,
    const char *zName,
    void *pUserData,
    fts5_tokenizer_v2 *pTokenizer,
    void (*xDestroy)(void*)
  );

  /* Find an existing tokenizer */
  int (*xFindTokenizer_v2)(
    fts5_api *pApi,
    const char *zName,
    void **ppUserData,
    fts5_tokenizer_v2 **ppTokenizer
  );
};

