        /* Handle thread signal mask */
        if (attrp->posix_attr_flags & POSIX_SPAWN_SETSIGMASK)
        {
            /* Set the signal mask (cannot fail) */
            sigprocmask(SIG_SETMASK, &attrp->posix_attr_sigmask, NULL);
